def test_normalize_email_uses_current_output(user_service):
    result = user_service.normalize_email(' Ada@EXAMPLE.COM ')
    assert result == 'ada@example.com'

def test_create_order_works(client, valid_token):
    response = client.post('/orders', json={'sku': 'A1'}, headers={'Authorization': f'Bearer {valid_token}'})
    assert response.status_code == 201
